g = input().strip()
parts = input().split()

A = int(parts[0])
B = int(parts[1]) if len(parts) > 1 else 0

if g == "BUFFER":
    print(A)
elif g == "NOT":
    print(1 - A)
elif g == "AND":
    print(A & B)
elif g == "OR":
    print(A | B)
elif g == "NAND":
    print(1 - (A & B))
elif g == "NOR":
    print(1 - (A | B))
elif g == "XOR":
    print(A ^ B)
elif g == "XNOR":
    print(1 - (A ^ B))
